    const bubbleRect = thinkingBubbleElement.getBoundingClientRect();
    // 자연 위치 기록 (고정 해제 판단에 사용)
    _bubbleNaturalScrollOffset = chatContainer.scrollTop + (bubbleRect.top - containerRect.top);
